const raw = $input.first().json.output;

let invoiceData;

try {
  // remove markdown if model added ```json ```
  const cleaned = raw.replace(/```json|```/g, "").trim();

  invoiceData = JSON.parse(cleaned);

} catch (error) {
  throw new Error("Failed to parse LLM JSON: " + error.message);
}

return {
  json: {
    invoice_data: invoiceData,
    document_id: $('Get Pending Invoices').item.json.id,
    user_id: $('Get Pending Invoices').item.json.user_id
  }
};

// Validate invoice data
const data = $input.item.json.invoice_data;
const errors = [];
const warnings = [];

// Required fields check
if (!data.invoice_number) errors.push('Missing invoice number');
if (!data.vendor_name) errors.push('Missing vendor name');
if (!data.total_amount) errors.push('Missing total amount');

// Validate line items calculations
if (data.line_items && data.line_items.length > 0) {
  let calculatedSubtotal = 0;
  data.line_items.forEach((item, idx) => {
    const itemTotal = item.quantity * item.unit_price;
    if (Math.abs(itemTotal - item.amount) > 0.01) {
      warnings.push(`Line item ${idx + 1} amount mismatch`);
    }
    calculatedSubtotal += item.amount;
  });

  // Check subtotal
  if (data.subtotal && Math.abs(calculatedSubtotal - data.subtotal) > 0.01) {
    warnings.push('Subtotal does not match line items sum');
  }

  // Check total = subtotal + tax
  const calculatedTotal = (data.subtotal || 0) + (data.tax || 0);
  if (data.total_amount && Math.abs(calculatedTotal - data.total_amount) > 0.01) {
    warnings.push('Total amount does not match subtotal + tax');
  }
}

// Calculate confidence score
let confidenceScore = 100;
confidenceScore -= errors.length * 20;
confidenceScore -= warnings.length * 10;
confidenceScore = Math.max(0, Math.min(100, confidenceScore));

// Determine validation status
let validationStatus = 'valid';
if (confidenceScore < 50) validationStatus = 'invalid';
else if (confidenceScore < 80) validationStatus = 'needs_review';

return {
  json: {
    invoice_data: data,
    document_id: $input.item.json.document_id,
    user_id: $input.item.json.user_id,
    validation: {
      status: validationStatus,
      confidence_score: confidenceScore,
      errors: errors,
      warnings: warnings
    }
  }
};

